<?php $q=$_GET;unset($q['pagina']);?><nav class="admin-report-pagination"><span>Página <?=$pagina?> de <?=$paginas?></span><?php if($pagina>1):$q['pagina']=$pagina-1;?><a href="?<?=htmlspecialchars(http_build_query($q),ENT_QUOTES,'UTF-8')?>">Anterior</a><?php endif;?><?php if($pagina<$paginas):$q['pagina']=$pagina+1;?><a href="?<?=htmlspecialchars(http_build_query($q),ENT_QUOTES,'UTF-8')?>">Siguiente</a><?php endif;?></nav>
